    // ── Pitch (Q/E), clamped ──────────────────────────────────
    if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
    if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);

    // ── Velocity ──────────────────────────────────────────────
    if (keys.w) {
        velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
    } else if (keys.s) {
        velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
    } else {
        velocityRef.current *= FRICTION;
        if (velocityRef.current < 0.01) velocityRef.current = 0;
