@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .distanceTracker {
        bottom: auto;
        top: 52px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: none;
        overflow: visible;
    }

    .linkModeButton {
        top: 12px;
        left: auto;
        right: 12px;
        padding: 8px 14px;
        font-size: 12px;
    }

    .linkModeIndicator {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        white-space: normal;
        font-size: 12px;
    }

    .labelInputPanel {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        min-width: 0;
        max-width: none;
    }

    .labelInputHeader {
        white-space: normal;
        font-size: 12px;
    }

    .rocketSpeedBar {
        width: 120px;
    }

    .rocketControls {
        display: none;
    }

    .rocketExitBtn {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .rocketTarget {
        bottom: 150px;
    }
}

