.universeContainer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(ellipse at center, #0a0e1a 0%, #000000 100%);
    touch-action: none;
    cursor: grab;
    z-index: 1000;
    overflow: hidden;
}

.universeContainer.grabbing {
    cursor: grabbing;
}

.backButton {
    position: absolute;
    top: 16px;
    left: 16px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.backButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.backButton svg {
    width: 18px;
    height: 18px;
    fill: #e0e0e0;
}

.distanceTracker {
    position: absolute;
    bottom: 184px;
    left: 16px;
    z-index: 1010;
    padding: 6px 12px;
    background: rgba(255, 255, 255, 0.04);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.35);
    font-size: 12px;
    font-family: monospace;
    pointer-events: none;
}

.loadingOverlay {
    position: absolute;
    inset: 0;
    z-index: 1040;
    display: flex;
    align-items: center;
    justify-content: center;
    background: radial-gradient(ellipse at center, rgba(10, 14, 26, 0.55) 0%, rgba(0, 0, 0, 0.72) 100%);
}

.loadingCard {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
    padding: 18px 22px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.14);
    border-radius: 14px;
}

.loadingSpinner {
    width: 26px;
    height: 26px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.15);
    border-top-color: rgba(95, 146, 255, 0.95);
    animation: universeSpin 0.8s linear infinite;
}

.loadingText {
    font-size: 12px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.82);
    letter-spacing: 0.02em;
}

@keyframes universeSpin {
    from {
        transform: rotate(0deg);
    }
    to {
        transform: rotate(360deg);
    }
}

.previewPanel {
    position: absolute;
    bottom: 16px;
    right: 16px;
    z-index: 1010;
    width: 320px;
    max-height: 340px;
    overflow-y: auto;
    padding: 20px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    color: #e0e0e0;
}

.previewClose {
    position: absolute;
    top: 10px;
    right: 10px;
    z-index: 1;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: rgba(255, 255, 255, 0.7);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
    padding: 0;
    font-family: inherit;
}

.previewClose:hover {
    background: rgba(0, 0, 0, 0.6);
    color: #fff;
}

.previewAuthor {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 12px;
}

.previewAvatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid rgba(255, 255, 255, 0.15);
}

.previewAuthorName {
    font-size: 13px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
}

.previewTitle {
    font-size: 16px;
    font-weight: 700;
    margin-bottom: 8px;
    color: #ffffff;
    line-height: 1.3;
}

.previewSnippet {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.55);
