        ellipse at center,
        rgba(95, 146, 255, 0.35) 0%,
        rgba(0, 0, 0, 0.9) 70%,
        rgba(0, 0, 0, 1) 100%
    );
    animation: rocketWarpInAnim 0.8s ease-out forwards;
}

@keyframes rocketWarpInAnim {
    0% {
        opacity: 0;
        transform: scale(1);
    }
    40% {
        opacity: 1;
    }
    100% {
        opacity: 0;
        transform: scale(3);
    }
}

