    right: 16px;
    left: 16px;
    bottom: 12px;
    max-height: 260px;
    box-sizing: border-box;
}

input.new_string:
.previewPanel {
    width: auto;
    right: 16px;
    left: 16px;
    bottom: 56px;
    max-height: 260px;
    box-sizing: border-box;
}

toolUseResult.oldString:
.previewPanel {
    width: auto;
    right: 16px;
