 89→                            ctx.lineWidth = 1;
 90→                            ctx.setLineDash([5, 10]);
 91→                            ctx.lineCap = 'round';
 92→                            ctx.beginPath();
 93→                            ctx.moveTo(ax, ay);
 94→                            ctx.lineTo(bx, by);
 95→                            ctx.stroke();
 96→                            ctx.restore();
 97→                            continue;
 98→                        }
 99→
100→                        if (isFocusedLine) {
101→                            // Focused: extra-wide outer glow
102→                            ctx.save();
103→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
104→                            ctx.lineWidth = 18;
105→                            ctx.lineCap = 'round';
106→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.7)`;
107→                            ctx.shadowBlur = 40;
108→                            ctx.setLineDash([]);
109→                            ctx.beginPath();
110→                            ctx.moveTo(ax, ay);
111→                            ctx.lineTo(bx, by);
112→                            ctx.stroke();
113→                            ctx.restore();
114→
115→                            // Focused: bright underglow
116→                            ctx.save();
117→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.25)`;
118→                            ctx.lineWidth = 8;
119→                            ctx.lineCap = 'round';
120→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.5)`;
121→                            ctx.shadowBlur = 24;
122→                            ctx.setLineDash([]);
123→                            ctx.beginPath();
124→                            ctx.moveTo(ax, ay);
125→                            ctx.lineTo(bx, by);
126→                            ctx.stroke();
127→                            ctx.restore();
128→
129→                            // Focused: solid body
130→                            ctx.save();
131→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.5)`;
132→                            ctx.lineWidth = 3;
133→                            ctx.lineCap = 'round';
134→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.6)`;
135→                            ctx.shadowBlur = 12;
136→                            ctx.setLineDash([]);
137→                            ctx.beginPath();
138→                            ctx.moveTo(ax, ay);
139→                            ctx.lineTo(bx, by);
140→                            ctx.stroke();
141→                            ctx.restore();
142→
143→                            // Focused: bright animated core
144→                            ctx.save();
145→                            ctx.strokeStyle = `rgba(255,255,255,0.8)`;
146→                            ctx.lineWidth = 1.5;
147→                            ctx.lineCap = 'round';
148→                            ctx.setLineDash([14, 10]);
149→                            ctx.lineDashOffset = time * 0.04;
150→                            ctx.beginPath();
151→                            ctx.moveTo(ax, ay);
152→                            ctx.lineTo(bx, by);
153→                            ctx.stroke();
154→                            ctx.restore();
155→                        } else if (isDimmedLine) {
156→                            // Dimmed: nearly invisible
157→                            ctx.save();
158→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.02)`;
159→                            ctx.lineWidth = 3;
160→                            ctx.lineCap = 'round';
161→                            ctx.setLineDash([]);
162→                            ctx.beginPath();
163→                            ctx.moveTo(ax, ay);
164→                            ctx.lineTo(bx, by);
165→                            ctx.stroke();
166→                            ctx.restore();
167→                        } else {
168→                            // Normal: triple-layer glow
169→
170→                            // Layer 1: Wide underglow
171→                            ctx.save();
172→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.06)`;
173→                            ctx.lineWidth = 8;
174→                            ctx.lineCap = 'round';
175→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
176→                            ctx.shadowBlur = 20;
177→                            ctx.setLineDash([]);
178→                            ctx.beginPath();
179→                            ctx.moveTo(ax, ay);
180→                            ctx.lineTo(bx, by);
181→                            ctx.stroke();
182→                            ctx.restore();
183→
184→                            // Layer 2: Medium body
185→                            ctx.save();
186→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
187→                            ctx.lineWidth = 3;
188→                            ctx.lineCap = 'round';
189→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
190→                            ctx.shadowBlur = 8;
191→                            ctx.setLineDash([]);
192→                            ctx.beginPath();
193→                            ctx.moveTo(ax, ay);
