201→                            ctx.lineWidth = 1.2;
202→                            ctx.lineCap = 'round';
203→                            ctx.setLineDash([14, 10]);
204→                            ctx.lineDashOffset = time * 0.04;
205→                            ctx.beginPath();
206→                            ctx.moveTo(ax, ay);
207→                            ctx.lineTo(bx, by);
208→                            ctx.stroke();
209→                            ctx.restore();
210→                        }
211→                    }
212→                }}
213→                perfectDrawEnabled={false}
214→                listening={false}
215→            />
216→            {/* Labels rendered as Konva Text for zoom correction */}
217→            {labels.map((link) => {
218→                const mx = (link.ax + link.bx) / 2;
219→                const my = (link.ay + link.by) / 2;
220→                return (
221→                    <Text
