 1→import { useState, useCallback } from 'react';
 2→import { requestConstellation } from '../../../../API/Api';
 3→
 4→const useConstellationLinkMode = (userId, session) => {
 5→    const [isLinkMode, setIsLinkMode] = useState(false);
 6→    const [firstStar, setFirstStar] = useState(null);
 7→    const [secondStar, setSecondStar] = useState(null);
 8→    const [isSubmitting, setIsSubmitting] = useState(false);
 9→
10→    const toggleLinkMode = useCallback(() => {
11→        setIsLinkMode(prev => {
12→            if (prev) {
13→                setFirstStar(null);
14→                setSecondStar(null);
15→            }
16→            return !prev;
17→        });
18→    }, []);
19→
20→    const cancelLinkMode = useCallback(() => {
21→        setIsLinkMode(false);
22→        setFirstStar(null);
23→        setSecondStar(null);
24→    }, []);
25→
26→    const submitLink = useCallback(async (label = '') => {
27→        if (!firstStar || !secondStar || isSubmitting) return;
28→        setIsSubmitting(true);
29→        try {
30→            const token = session?.access_token;
31→            const result = await requestConstellation(token, firstStar.id, secondStar.id, label);
32→            setIsLinkMode(false);
33→            setFirstStar(null);
34→            setSecondStar(null);
35→            return { step: 'complete', result };
36→        } catch (err) {
37→            return { error: err.message || 'Failed to create constellation link' };
38→        } finally {
39→            setIsSubmitting(false);
40→        }
41→    }, [firstStar, secondStar, isSubmitting, session]);
42→
43→    const handleStarClickInLinkMode = useCallback((post) => {
44→        if (!isLinkMode || isSubmitting) return false;
45→
46→        const postOwnerId = post.users?.id ?? post.user_id;
47→
48→        if (!firstStar) {
49→            // First click: must be user's own star
50→            if (postOwnerId !== userId) {
51→                return { error: 'Select one of your own stars first' };
52→            }
53→            setFirstStar(post);
54→            return { step: 'first', post };
55→        }
56→
57→        // Second click: must be a different user's star
58→        if (postOwnerId === userId) {
59→            return { error: 'Second star must belong to another user' };
60→        }
61→
62→        // Set second star and prompt for label instead of submitting immediately
63→        setSecondStar(post);
64→        return { step: 'enter_label' };
65→    }, [isLinkMode, isSubmitting, firstStar, userId]);
66→
67→    const linkModeStatus = isLinkMode
68→        ? (secondStar ? 'enter_label' : (firstStar ? 'select_second' : 'select_first'))
69→        : 'inactive';
70→
71→    return {
72→        isLinkMode,
73→        firstStar,
74→        secondStar,
75→        isSubmitting,
76→        linkModeStatus,
77→        toggleLinkMode,
78→        cancelLinkMode,
79→        handleStarClickInLinkMode,
80→        submitLink,
81→    };
82→};
83→
84→export default useConstellationLinkMode;
