 634→            if (!post) return;
 635→
 636→            const snapshot = rocketMode.getSessionSnapshot();
 637→            const sessionData = {
 638→                ...snapshot,
 639→                galaxyUserId: selectedGalaxyUserIdRef.current,
 640→                postId: post.id,
 641→            };
 642→            try { sessionStorage.setItem('rocketSession', JSON.stringify(sessionData)); } catch { /* storage full */ }
 643→            navigate(`/home/post/${post.id}`, { state: { fromRocket: true } });
 644→        });
 645→    }, [rocketMode, navigate]);
 646→
 647→    // Restore rocket session on mount (reverse warp)
 648→    useEffect(() => {
 649→        const raw = sessionStorage.getItem('rocketSession');
 650→        if (!raw) return;
 651→        try {
 652→            const session = JSON.parse(raw);
 653→            // Discard if older than 5 minutes
 654→            if (Date.now() - session.timestamp > 5 * 60 * 1000) {
 655→                sessionStorage.removeItem('rocketSession');
 656→                return;
 657→            }
 658→            sessionStorage.removeItem('rocketSession');
 659→            setReverseWarpActive(true);
 660→            pendingRocketRestoreRef.current = session;
 661→        } catch {
 662→            sessionStorage.removeItem('rocketSession');
 663→        }
 664→    }, []);
 665→
 666→    // Once posts load, restore rocket mode from session
 667→    useEffect(() => {
 668→        const session = pendingRocketRestoreRef.current;
