 675→        });
 676→
 677→        if (galaxyPosts.length === 0) {
 678→            pendingRocketRestoreRef.current = null;
 679→            setReverseWarpActive(false);
 680→            return;
 681→        }
 682→
 683→        pendingRocketRestoreRef.current = null;
