170→export const deleteConstellationService = async (userId, constellationId) => {
171→    if (!userId || !constellationId) {
172→        throw { status: 400, error: 'userId and constellationId are required' };
173→    }
174→
175→    const { data: constellation, error: errorFetch } = await supabase
176→        .from('constellations')
177→        .select('user_id_a, user_id_b')
178→        .eq('id', constellationId)
179→        .maybeSingle();
180→
181→    if (errorFetch) {
182→        console.error('supabase error fetching constellation for delete:', errorFetch.message);
183→        throw { status: 500, error: 'error fetching constellation' };
184→    }
185→    if (!constellation) {
186→        throw { status: 404, error: 'constellation not found' };
187→    }
188→
189→    const isParticipant = constellation.user_id_a === userId || constellation.user_id_b === userId;
190→    if (!isParticipant) {
191→        throw { status: 403, error: 'you are not a participant of this constellation' };
192→    }
193→
194→    const { error: errorDelete } = await supabase
195→        .from('constellations')
196→        .delete()
197→        .eq('id', constellationId);
198→
199→    if (errorDelete) {
200→        console.error('supabase error deleting constellation:', errorDelete.message);
201→        throw { status: 500, error: 'error deleting constellation' };
202→    }
203→
204→    return { message: 'constellation deleted' };
205→};
