459→export const computeConstellationPullOffsets = (
460→    constellations,
461→    starPositions,
462→    options = {}
463→) => {
464→    const offsets = new Map();
465→    if (!Array.isArray(constellations) || constellations.length === 0) return offsets;
466→    if (!(starPositions instanceof Map) || starPositions.size === 0) return offsets;
467→
468→    const restLength = Number.isFinite(options.restLength) ? options.restLength : 200;
469→    const stiffness = Number.isFinite(options.stiffness) ? options.stiffness : 0.03;
470→    const maxMagnitude = Number.isFinite(options.maxMagnitude) ? options.maxMagnitude : 120;
471→
472→    for (const link of constellations) {
473→        const posA = starPositions.get(link.star_id_a);
474→        const posB = starPositions.get(link.star_id_b);
475→        if (!posA || !posB) continue;
476→
477→        const dx = posB.x - posA.x;
478→        const dy = posB.y - posA.y;
479→        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
480→        const displacement = dist - restLength;
481→
482→        const fx = (dx / dist) * displacement * stiffness;
483→        const fy = (dy / dist) * displacement * stiffness;
484→
485→        // Accumulate for star A (pull toward B)
486→        if (!offsets.has(link.star_id_a)) {
487→            offsets.set(link.star_id_a, { dx: 0, dy: 0 });
488→        }
489→        const oA = offsets.get(link.star_id_a);
490→        oA.dx += fx;
491→        oA.dy += fy;
492→
493→        // Accumulate for star B (pull toward A)
494→        if (!offsets.has(link.star_id_b)) {
495→            offsets.set(link.star_id_b, { dx: 0, dy: 0 });
496→        }
497→        const oB = offsets.get(link.star_id_b);
498→        oB.dx -= fx;
499→        oB.dy -= fy;
500→    }
501→
502→    // Clamp magnitudes
503→    for (const [postId, offset] of offsets.entries()) {
504→        const mag = Math.sqrt(offset.dx * offset.dx + offset.dy * offset.dy);
505→        if (mag > maxMagnitude) {
506→            offsets.set(postId, {
507→                dx: (offset.dx / mag) * maxMagnitude,
508→                dy: (offset.dy / mag) * maxMagnitude,
509→            });
510→        }
511→    }
512→
513→    return offsets;
514→};
